// RSA Encryption/Decryption using Web Crypto API

export const encryptMessage = async (message, publicKeyB64) => {
  try {
    // Decode base64 public key
    const publicKeyPem = atob(publicKeyB64);
    
    // Import public key
    const binaryDer = pemToBinary(publicKeyPem);
    const publicKey = await window.crypto.subtle.importKey(
      'spki',
      binaryDer,
      {
        name: 'RSA-OAEP',
        hash: 'SHA-256',
      },
      true,
      ['encrypt']
    );
    
    // Encrypt message
    const encoder = new TextEncoder();
    const data = encoder.encode(message);
    const encrypted = await window.crypto.subtle.encrypt(
      {
        name: 'RSA-OAEP'
      },
      publicKey,
      data
    );
    
    // Convert to base64
    return arrayBufferToBase64(encrypted);
  } catch (error) {
    console.error('Encryption error:', error);
    throw error;
  }
};

export const decryptMessage = async (encryptedMessageB64, privateKeyB64) => {
  try {
    // Decode base64 private key
    const privateKeyPem = atob(privateKeyB64);
    
    // Import private key
    const binaryDer = pemToBinary(privateKeyPem);
    const privateKey = await window.crypto.subtle.importKey(
      'pkcs8',
      binaryDer,
      {
        name: 'RSA-OAEP',
        hash: 'SHA-256',
      },
      true,
      ['decrypt']
    );
    
    // Decrypt message
    const encryptedData = base64ToArrayBuffer(encryptedMessageB64);
    const decrypted = await window.crypto.subtle.decrypt(
      {
        name: 'RSA-OAEP'
      },
      privateKey,
      encryptedData
    );
    
    // Convert to string
    const decoder = new TextDecoder();
    return decoder.decode(decrypted);
  } catch (error) {
    console.error('Decryption error:', error);
    return '[Encrypted Message]';
  }
};

function pemToBinary(pem) {
  const lines = pem.split('\n');
  const encoded = lines
    .filter(line => !line.startsWith('-----'))
    .join('');
  const binary = atob(encoded);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

function arrayBufferToBase64(buffer) {
  const bytes = new Uint8Array(buffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function base64ToArrayBuffer(base64) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}